CREATE TABLE IF NOT EXISTS t_p61016064_digital_innovation_i.wb_case_process_links (id SERIAL PRIMARY KEY, case_id INTEGER NOT NULL, process_id INTEGER NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE (case_id, process_id)); CREATE TABLE IF NOT EXISTS t_p61016064_digital_innovation_i.wb_pain_points (id SERIAL PRIMARY KEY, case_id INTEGER NOT NULL, process_step_id INTEGER, pain_type TEXT NOT NULL DEFAULT 'manual_work', description TEXT NOT NULL, impact_level TEXT NOT NULL DEFAULT 'medium', frequency TEXT, root_cause TEXT, is_archived BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE INDEX IF NOT EXISTS idx_wb_pain_case ON t_p61016064_digital_innovation_i.wb_pain_points(case_id);